def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) + (capacity % 5) * 3.7
            for x in range(1, int(capacity) + 3):
                if x % 3 == 0:
                    priority += np.cbrt(ratio * x) / (x + epsilon)
                elif x % 2 == 0:
                    priority -= np.sin(ratio + x)
                else:
                    priority += np.exp(-x / (ratio + epsilon))
            if capacity % 4 == 3:
                priority *= 1.3 * np.log(capacity + 1)
            else:
                priority /= 1.2 + epsilon
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.sqrt(capacity + 1)
            for y in range(1, int(item) * 2 + 1):
                if y % 4 == 0:
                    priority += (y / (capacity + 2)) ** 3
                elif y % 2 == 1:
                    priority -= np.tanh(y / (item + epsilon))
                else:
                    priority += y * 0.05
            priority = max(priority, 0)
        elif 0.5 < ratio <= 2:
            priority = -np.log(1 - (ratio / 2) + epsilon) * (capacity / (item + epsilon))
            factor = 1
            for z in range(1, 7):
                factor *= abs(np.cos(ratio * z)) + (z / (capacity + 1))
                if factor > 10:
                    break
            priority *= factor
        elif 0.1 < ratio <= 0.5:
            total_sum = 0.0
            for w in range(1, int(capacity) * 2 + 1):
                val = ((-1)**w) * ((ratio ** w) / (w ** 1.5 + epsilon))
                total_sum += val
            priority = abs(total_sum) + np.sqrt(capacity) * 0.7
        else:
            priority = np.exp(-ratio * capacity) + 0.1 * ratio * capacity
            for v in range(1, int(capacity / 2) + 2):
                if v % 5 == 0:
                    priority -= np.log(v + ratio + epsilon)
                else:
                    priority += (v * ratio) / (capacity + 1)
            priority = max(priority, 0.1)
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff) + 3):
                if p % 3 == 0:
                    penalty += np.sqrt(p + 1)
                elif p % 2 == 0:
                    penalty -= p * 0.05
                else:
                    penalty += np.log(p + 2)
            penalty = max(penalty, 0)
            priority += penalty
        def is_prime(n):
            if n < 2:
                return False
            for t in range(2, int(np.sqrt(n)) + 1):
                if n % t == 0:
                    return False
            return True
        if is_prime(int(capacity)):
            priority *= 1.15 + 0.05 * np.sin(item + capacity)
        else:
            priority *= 0.85
        priorities[i] = priority
    return priorities
